function platformBrandColor(string $key): string
{
    global $platformBrandColors;
    return $platformBrandColors[$key] ?? '#64748B';
}

function platformSvg(string $key, int $size = 24): string
{
    global $platformSvgs;
    if (!isset($platformSvgs[$key])) {
        return '';
    }
    return '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="' . (int) $size . '" height="' . (int) $size . '" fill="none" stroke="none" aria-hidden="true">' . $platformSvgs[$key] . '</svg>';
}

/** Brand-colored logo (YouTube red, Telegram blue, etc.). */
function platformSvgBrand(string $key, int $size = 24): string
{
    $svg = platformSvg($key, $size);
    if ($svg === '') {
        return '';
    }
    $color = platformBrandColor($key);
    return str_replace('<svg ', '<svg class="platform-logo-svg" style="color:' . htmlspecialchars($color, ENT_QUOTES, 'UTF-8') . '" ', $svg);
}

function platformKeyFromCategory(string $category): string
{
    global $platformSvgs;
    $keys = array_keys($platformSvgs);
    usort($keys, static function ($a, $b) {
        return strlen($b) - strlen($a);
    });
    foreach ($keys as $key) {
        if ($key === 'Category') {
            continue;
        }
        if (stripos($category, $key) !== false) {
            return $key;
        }
    }
    return 'Category';
}

/** Render horizontal platform filter strip HTML. */
function platformFilterStrip(string $basePath, string $activePlatform = '', string $search = '', array $extraParams = []): string
{
    $html = '<div class="platform-strip-wrap"><div class="platform-strip" role="tablist" aria-label="Filter by network">';
    $allParams = $extraParams;
    if ($search !== '') {
        $allParams['q'] = $search;
    }
    $allUrl = path($basePath) . ($allParams ? '?' . http_build_query($allParams) : '');
    $html .= '<a class="platform-chip' . ($activePlatform === '' ? ' active' : '') . '" href="' . htmlspecialchars($allUrl, ENT_QUOTES, 'UTF-8') . '" title="All networks"><span class="platform-chip-label">All</span></a>';

    foreach (platformFilterList() as $pKey => $pInfo) {
        $params = array_merge($extraParams, ['platform' => $pKey]);
        if ($search !== '') {
            $params['q'] = $search;
        }
        $url = path($basePath) . '?' . http_build_query($params);
        $isActive = $activePlatform === $pKey;
        $html .= '<a class="platform-chip' . ($isActive ? ' active' : '') . '" href="' . htmlspecialchars($url, ENT_QUOTES, 'UTF-8') . '" title="' . htmlspecialchars($pInfo['title'], ENT_QUOTES, 'UTF-8') . '">';
        $html .= '<span class="platform-chip-icon">' . platformSvgBrand($pKey, 22) . '</span>';
        $html .= '<span class="platform-chip-label">' . htmlspecialchars($pInfo['label'], ENT_QUOTES, 'UTF-8') . '</span>';
        $html .= '</a>';
    }
    $html .= '</div></div>';
    return $html;
}
